21→export const extractBannerImage = (
22→  rawContent: string | null | undefined,
23→  images?: string | string[] | null,
24→): string | null => {
25→  if (images) {
26→    if (typeof images === 'string') {
27→      try {
28→        const parsed = JSON.parse(images);
29→        if (Array.isArray(parsed) && parsed.length > 0) return parsed[0];
30→      } catch {
31→        if (images.startsWith('http')) return images;
32→      }
33→    }
34→    if (Array.isArray(images) && images.length > 0) return images[0];
35→  }
36→  if (!rawContent) return null;
37→  try {
38→    const parsed = JSON.parse(rawContent);
39→    const findImage = (node: any): string | null => {
40→      if (node.type === 'image' && node.src) return node.src;
41→      if (node.children) {
42→        for (const child of node.children) {
43→          const found = findImage(child);
44→          if (found) return found;
45→        }
46→      }
47→      return null;
48→    };
49→    return findImage(parsed.root ?? parsed);
50→  } catch {
51→    return null;
52→  }
53→};
